args.sparql:
SELECT ?artist ?artistLabel (COUNT(DISTINCT ?album) AS ?count)
WHERE {
  ?album wdt:P31 wd:Q5711748;
         p:P1617 ?statement.
  ?statement ps:P1617 ?sales;
            pq:P10611 wd:Q8893772.
  ?album wdt:P175 ?artist.
  ?artist rdfs:label ?artistLabel.
  FILTER (LANG(?artistLabel) = "en")
}
GROUP BY ?artist ?artistLabel
ORDER BY DESC(?count)
LIMIT 1
